async (params, browser) => {
  // Open MyFitnessPal search
  await browser.open(`https://www.myfitnesspal.com/food/search?search=${params.query}`)

  // Wait for results
  await browser.waitForSelector('.food-search-results, [class*="search-results"], ul, .content', 15000)

  // Let results render
  await browser.wait(2500)

  // Extract results
  const search_results = await browser.evaluate(`const results = []; document.querySelectorAll('.food-search-results li, [class*="search-result"], [class*="FoodItem"]').forEach((el, i) => { if (i < 15) { const nameEl = el.querySelector('a, .food-name, [class*="name"]'); const calEl = el.querySelector('.cal, [class*="calorie"], [class*="nutrition"]'); const servingEl = el.querySelector('.serving, [class*="serving"]'); results.push({ name: nameEl?.textContent?.trim() || '', url: nameEl?.href || '', calories: calEl?.textContent?.trim() || '', serving: servingEl?.textContent?.trim() || '' }); } }); return { query: '' + params.query + '', result_count: results.length, results };`)

  return search_results
}
